import type { Page } from '@playwright/test';

import { adminStateFile } from '../../../helpers/user-data';
import { expect, test } from '../../support/fixtures/parallel-test';

test.setTimeout(120_000);

test.use({ storageState: adminStateFile });

const viewportSizes = [
  { height: 740, label: 'narrow mobile', width: 320 },
  { height: 844, label: 'mobile', width: 390 },
  { height: 900, label: 'desktop', width: 1440 },
] as const;

const readPageLayout = async (page: Page) =>
  page.evaluate(() => {
    const visibleElements = [...document.querySelectorAll<HTMLElement>('*')]
      .filter((element) => {
        const rect = element.getBoundingClientRect();
        const style = window.getComputedStyle(element);

        return (
          rect.width > 0 &&
          rect.height > 0 &&
          style.visibility !== 'hidden' &&
          style.display !== 'none'
        );
      })
      .map((element) => {
        const rect = element.getBoundingClientRect();

        return {
          element,
          rect,
        };
      });
    const controls = [
      ...document.querySelectorAll<HTMLElement>(
        'a[href], button, input, select, textarea, [role="button"], [role="link"]',
      ),
    ].filter((element) => {
      const rect = element.getBoundingClientRect();
      const style = window.getComputedStyle(element);

      return (
        rect.width > 0 &&
        rect.height > 0 &&
        style.visibility !== 'hidden' &&
        style.display !== 'none'
      );
    });
    const horizontallyClippedControls = controls.filter((element) => {
      const rect = element.getBoundingClientRect();

      return rect.left < -1 || rect.right > window.innerWidth + 1;
    });
    const horizontallyOverflowingElements = visibleElements.filter(
      ({ rect }) => rect.left < -1 || rect.right > window.innerWidth + 1,
    );

    return {
      appError: /application error|server error|hydration/i.test(
        document.body.innerText,
      ),
      horizontalOverflow:
        document.documentElement.scrollWidth > window.innerWidth + 1 &&
        horizontallyOverflowingElements.length > 0,
      horizontallyClippedControlCount: horizontallyClippedControls.length,
      horizontallyOverflowingElementCount:
        horizontallyOverflowingElements.length,
    };
  });

test('template pages have stable layouts across viewports @templates', async ({
  page,
  templateCategories,
  templates,
}) => {
  const category = templateCategories[0];
  if (!category) {
    throw new Error('Expected seeded template category for viewport coverage');
  }
  const template = templates[0];
  if (!template) {
    throw new Error('Expected seeded template for viewport coverage');
  }

  const routes = [
    {
      expectedHeading: 'Event templates',
      extraText: category.title,
      path: '/templates',
    },
    {
      expectedHeading: 'Create template',
      extraText: 'Simple Registration Setup',
      path: '/templates/create',
    },
    {
      expectedHeading: template.title,
      extraText: 'Registration Options',
      path: `/templates/${template.id}`,
    },
    {
      expectedHeading: 'Edit template',
      extraText: 'Reusable add-ons',
      path: `/templates/${template.id}/edit`,
    },
    {
      expectedHeading: `Create ${template.title} event`,
      extraText: 'Event Details',
      path: `/templates/${template.id}/create-event`,
    },
  ] as const;

  for (const viewport of viewportSizes) {
    await test.step(`${viewport.label} viewport`, async () => {
      await page.setViewportSize(viewport);

      for (const route of routes) {
        await test.step(route.path, async () => {
          await page.goto(route.path);

          await expect(
            page.getByRole('heading', {
              level: 1,
              name: route.expectedHeading,
            }),
          ).toBeVisible();
          await expect(
            page.getByText(route.extraText, { exact: false }).first(),
          ).toBeVisible();
          await expect(readPageLayout(page)).resolves.toEqual({
            appError: false,
            horizontalOverflow: false,
            horizontallyClippedControlCount: 0,
            horizontallyOverflowingElementCount: 0,
          });
        });
      }
    });
  }
});

